// ============================================================
// E-Mail Bericht erstellen
// Laeuft einmal für alle Items (eine Zeile pro aktiver Pflanze)
// Gibt genau ein Item zurueck: { html, subject, toEmail }
// ============================================================

const plants = $input.all();
const email  = $('Konfiguration').first().json.email;
const prefix = $('Konfiguration').first().json.betreff_prefix;

if (!plants || plants.length === 0) {
  return [{ json: {
    html:    '<p>Keine aktiven Pflanzen in der Datenbank (zucht.aktuell = TRUE).</p>',
    subject: prefix + ' – Keine aktiven Pflanzen',
    toEmail: email
  } }];
}

const today = new Date();
const formattedDate = today.toLocaleDateString('de-DE', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Phasenfarben – Schlüssel müssen mit den Werten in sorten.w1-w30 und licht.phase_name übereinstimmen
const phaseColors = {
  'Keimphase':        '#4a9eca',
  'Vegetative Phase': '#5cb85c',
  'Bluetephase':      '#f0a500',
  'Erntephase':       '#888888',
  'Geerntet':         '#555555'
};

// ── Tabellenzeilen ──────────────────────────────────────────
const tableRows = plants.map(function(item) {
  const p  = item.json;
  const bg = phaseColors[p.aktuelle_phase] || '#cccccc';

  // Lichtangabe
  const licht = (p.stunden_an !== '-' && p.stunden_aus !== '-')
                ? p.stunden_an + 'h / ' + p.stunden_aus + 'h'
                : '–';

  // Canna-Bio-Dosierungen: nur Produkte mit Wert > 0 anzeigen
  const produkte = [
    { name: 'Bio Vega',   ml: Number(p.bio_vega_ml) },
    { name: 'Bio Flores', ml: Number(p.bio_flores_ml) },
    { name: 'Boost',      ml: Number(p.boost_ml) },
    { name: 'Rhizotonic', ml: Number(p.rhizotonic_ml) }
  ].filter(function(x) { return x.ml > 0; })
   .map(function(x) { return '<b>' + x.name + '</b> ' + x.ml + ' ml/L'; })
   .join(' &nbsp;|&nbsp; ');

  // EC-Bereich
  const ec = (p.ec_min && p.ec_max && p.ec_min !== '-' && p.ec_min !== '0.00')
             ? 'EC ' + p.ec_min + '–' + p.ec_max + ' &nbsp;|&nbsp; pH 6,0–6,5'
             : 'pH 6,0–6,5';

  const duengung = produkte
    ? produkte + '<br><small style="color:#777;">' + ec + '</small>'
    : '<i style="color:#999;">Nur Wasser</i><br><small style="color:#777;">' + ec + '</small>';

  // Unterzeile: Wochenhinweis aus Düngeplan
  const unterzeile = p.duenger_hinweis || '–';

  return '<tr>' +
    '<td style="padding:10px;border:1px solid #ddd;font-weight:bold;vertical-align:top;">' +
      p.pflanzname +
      '<br><small style="font-weight:normal;color:#666;">' +
        p.sorte + ' &bull; ' + (p.pflanztyp || '') + '<br>' +
        'THC ' + (p.thc || '?') + '% / CBD ' + (p.cbd || '?') + '%' +
      '</small>' +
    '</td>' +
    '<td style="padding:10px;border:1px solid #ddd;text-align:center;vertical-align:top;">' +
      p.aktuelle_woche +
      '<br><small style="color:#999;font-weight:normal;">' + (p.duenger_phase || '') + '</small>' +
    '</td>' +
    '<td style="padding:10px;border:1px solid #ddd;background:' + bg + ';color:#fff;font-weight:bold;vertical-align:top;">' +
      (p.aktuelle_phase || '–') +
    '</td>' +
    '<td style="padding:10px;border:1px solid #ddd;font-size:.9em;vertical-align:top;">' +
      duengung +
    '</td>' +
    '<td style="padding:10px;border:1px solid #ddd;text-align:center;font-weight:bold;vertical-align:top;">' +
      licht +
    '</td>' +
    '</tr>' +
    '<tr><td colspan="5" style="padding:4px 10px 10px;border:1px solid #ddd;background:#f9f9f9;font-size:.82em;color:#666;">' +
      '<i>' + unterzeile + '</i>' +
    '</td></tr>';
}).join('');

// ── Phasen-Legende ───────────────────────────────────────────
const legendItems = [
  { name: 'Keimphase',        info: '18h/6h &ndash; Rhizotonic 2 ml/L',                           color: '#4a9eca' },
  { name: 'Vegetative Phase', info: '18h/6h &ndash; Bio Vega 1–3 ml/L + Rhizotonic 2 ml/L',       color: '#5cb85c' },
  { name: 'Blütephase',       info: '12h/12h &ndash; Bio Flores 2–4 ml/L + Boost 1–3 ml/L',       color: '#f0a500' },
  { name: 'Erntephase',       info: '12h/12h &ndash; Nur Wasser (Spülen)',                         color: '#888888' }
];
const legendHtml = legendItems.map(function(l) {
  return '<li style="margin-bottom:5px;"><span style="background:' + l.color +
    ';color:#fff;padding:2px 8px;border-radius:3px;font-weight:bold;">' +
    l.name + '</span>&nbsp; ' + l.info + '</li>';
}).join('');

// ── Betreff-Wochen-Label ─────────────────────────────────────
const weeks  = plants.map(function(p) { return Number(p.json.aktuelle_woche); });
const minW   = Math.min.apply(null, weeks);
const maxW   = Math.max.apply(null, weeks);
const wLabel = minW === maxW ? 'Woche ' + minW : 'Woche ' + minW + '–' + maxW;

// ── HTML-Mail zusammenbauen ──────────────────────────────────
const html =
  '<!DOCTYPE html><html><head><meta charset="UTF-8"></head>' +
  '<body style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto;padding:20px;">' +
  '<h2 style="color:#2d5a27;border-bottom:2px solid #2d5a27;padding-bottom:10px;">' +
    prefix + ' &ndash; ' + wLabel +
  '</h2>' +
  '<p style="color:#666;margin-top:0;">Erstellt am: ' + formattedDate + '</p>' +
  '<table style="width:100%;border-collapse:collapse;margin-top:15px;">' +
    '<thead><tr style="background:#2d5a27;color:#fff;">' +
      '<th style="padding:12px;text-align:left;">Pflanze / Sorte</th>' +
      '<th style="padding:12px;text-align:center;">Woche</th>' +
      '<th style="padding:12px;text-align:left;">Pflanzenphase</th>' +
      '<th style="padding:12px;text-align:left;">Düngegabe (Canna Bio / 1 L)</th>' +
      '<th style="padding:12px;text-align:center;">Lichtgabe</th>' +
    '</tr></thead>' +
    '<tbody>' + tableRows + '</tbody>' +
  '</table>' +
  '<div style="margin-top:28px;padding:14px;background:#f0f4f0;border-radius:6px;">' +
    '<h3 style="margin-top:0;color:#2d5a27;">Phasen-Legende</h3>' +
    '<ul style="margin:0;padding-left:20px;">' + legendHtml + '</ul>' +
    '<p style="margin:10px 0 0;font-size:.82em;color:#888;">Reihenfolge beim Anmischen: erst Rhizotonic, dann Hauptdünger, zuletzt Boost. Frisch anmischen, nicht länger als 24 h stehen lassen.</p>' +
  '</div>' +
  '<p style="margin-top:28px;font-size:.78em;color:#aaa;">' +
    'Automatisch generiert | Quelle: PostgreSQL Cannabis-DB' +
  '</p>' +
  '</body></html>';

return [{ json: {
  html:    html,
  subject: prefix + ' ' + wLabel + ' – ' + formattedDate,
  toEmail: email
} }];
